ALTER TABLE analyses
  ADD COLUMN file_key VARCHAR(512) NULL AFTER temp_session_id,
  ADD COLUMN file_hash VARCHAR(64) NULL AFTER file_url,
  ADD COLUMN ocr_text_key VARCHAR(512) NULL AFTER error_code,
  ADD COLUMN ocr_text_url TEXT NULL AFTER ocr_text_key,
  ADD COLUMN ocr_meta JSON NULL AFTER ocr_text_url,
  ADD COLUMN proof_of_read JSON NULL AFTER ocr_meta,
  ADD COLUMN preview_json JSON NULL AFTER proof_of_read,
  ADD COLUMN rubric_version VARCHAR(16) NULL AFTER full_json,
  ADD COLUMN expires_at TIMESTAMP NULL AFTER rubric_version,
  ADD COLUMN raw_extraction_output TEXT NULL AFTER expires_at,
  ADD COLUMN raw_analysis_output TEXT NULL AFTER raw_extraction_output;

ALTER TABLE analyses MODIFY COLUMN status ENUM('processing','temp','persisted_email_verified','full_unlocked','failed','purged') NOT NULL DEFAULT 'processing';

ALTER TABLE analyses MODIFY COLUMN file_url TEXT NULL;

ALTER TABLE leads
  ADD COLUMN email_verified_at TIMESTAMP NULL,
  ADD COLUMN phone_verified_at TIMESTAMP NULL;

CREATE INDEX idx_analyses_file_hash ON analyses(file_hash);
CREATE INDEX idx_analyses_status_expires ON analyses(status, expires_at);
CREATE INDEX idx_analyses_lead_created ON analyses(lead_id, created_at);

